mapper.select:
SELECT COUNT(*)
FROM TBL_MEMBER
WHERE MEMBERID = #{memberId}

SELECT COUNT(*)
FROM TBL_MEMBER
WHERE EMAIL = #{email}

SELECT COUNT(*)
FROM TBL_COMPANY
WHERE BIZ_NO = #{bizNo}

SELECT NVL(MAX(APPROVED_YN), 0)
FROM TBL_COMPANY
WHERE FK_MEMBERID = #{memberId}

SELECT c.REJECT_REASON
FROM TBL_COMPANY c
WHERE c.FK_MEMBERID = #{memberId}

SELECT FAIL_COUNT
FROM TBL_LOGIN_SECURITY
WHERE FK_MEMBERID = #{memberId}

SELECT PHONE
FROM TBL_MEMBER
WHERE MEMBERID = #{memberId}

SELECT MEMBERID
FROM TBL_MEMBER
WHERE NAME = #{name}
  AND EMAIL = #{email}
  AND PHONE = #{phone}
  AND TYPE = 0

SELECT MEMBERID
FROM TBL_MEMBER
WHERE MEMBERID = #{memberId}
  AND NAME = #{name}
  AND PHONE = #{phone}
  AND TYPE = 0

SELECT M.MEMBERID
FROM TBL_MEMBER M
JOIN TBL_COMPANY C
  ON M.MEMBERID = C.FK_MEMBERID
WHERE C.BIZ_NO = #{bizNo}
  AND M.NAME = #{name}
  AND M.EMAIL = #{email}
  AND M.TYPE = 1

SELECT M.MEMBERID
FROM TBL_MEMBER M
JOIN TBL_COMPANY C
  ON M.MEMBERID = C.FK_MEMBERID
WHERE M.MEMBERID = #{memberId}
  AND C.BIZ_NO = #{bizNo}
  AND M.PHONE = #{phone}
  AND M.TYPE = 1

SELECT RT_VALUE
FROM TBL_REFRESHTOKEN
WHERE MEMBERID = #{memberId}
